"""
Parameterized generator for GH1020_transformers_20318.

Source PR:    https://github.com/huggingface/transformers/pull/20318
Source Issue: https://github.com/huggingface/transformers/issues/19733

Seed varies: renames 'accelerate' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1020_transformers_20318'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1020_transformers_20318'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('accelerate', 'accelerate' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1020_transformers_20318',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'huggingface/transformers',
                "pr_number": 20318,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/huggingface/transformers/pull/20318",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'examples/pytorch/test_accelerate_examples.py': '# coding=utf-8\n# Copyright 2018 HuggingFace Inc..\n#\n# Licensed under the Apache License, Version 2.0 (the "License");\n# you may not use this file except in compliance with the License.\n# You may obtain a copy of the License at\n#\n#     http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing, software\n# distributed under the License is distributed on an "AS IS" BASIS,\n# WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n# See the License for the specific language governing permissions and\n# limitations under the License.\n\n\nimport argparse\nimport json\nimport logging\nimport os\nimport shutil\nimport sys\nimport tempfile\nfrom unittest import mock\n\nimport torch\n\nfrom accelerate.utils import write_basic_config\nfrom transformers.testing_utils import TestCasePlus, get_gpu_count, is_flaky, run_command, slow, torch_device\nfrom transformers.utils import is_apex_available\n\n\nlogging.basicConfig(level=logging.DEBUG)\n\nlogger = logging.getLogger()\n\n\ndef get_setup_file():\n    parser = argparse.ArgumentParser()\n    parser.add_argument("-f")\n    args = parser.parse_args()\n    return args.f\n\n\ndef get_results(output_dir):\n    results = {}\n    path = os.path.join(output_dir, "all_results.json")\n    if os.path.exists(path):\n        with open(path, "r") as f:\n            results = json.load(f)\n    else:\n        raise ValueError(f"can\'t find {path}")\n    return results\n\n\ndef is_cuda_and_apex_available():\n    is_using_cuda = torch.cuda.is_available() and torch_device == "cuda"\n    return is_using_cuda and is_apex_available()\n\n\nstream_handler = logging.StreamHandler(sys.stdout)\nlogger.addHandler(stream_handler)\n\n\nclass ExamplesTestsNoTrainer(TestCasePlus):\n    @classmethod\n    def setUpClass(cls):\n        # Write Accelerate config, will pick up on CPU, GPU, and multi-GPU\n        cls.tmpdir = tempfile.mkdtemp()\n        cls.configPath = os.path.join(cls.tmpdir, "default_config.yml")\n        write_basic_config(save_location=cls.configPath)\n        cls._launch_args = ["accelerate", "launch", "--config_file", cls.configPath]\n\n    @classmethod\n    def tearDownClass(cls):\n        shutil.rmtree(cls.tmpdir)\n\n    @mock.patch.dict(os.environ, {"WANDB_MODE": "offline"})\n    def test_run_glue_no_trainer(self):\n        tmp_dir = self.get_auto_remove_tmp_dir()\n        testargs = f"""\n            {self.examples_dir}/pytorch/text-classification/run_glue_no_trainer.py\n            --model_name_or_path distilbert-base-uncased\n            --output_dir {tmp_dir}\n            --train_file ./tests/fixtures/tests_samples/MRPC/train.csv\n            --validation_file ./tests/fixtures/tests_samples/MRPC/dev.csv\n            --per_device_train_batch_size=2\n            --per_device_eval_batch_size=1\n            --learning_rate=1e-4\n            --seed=42\n            --checkpointing_steps epoch\n            --with_tracking\n        """.split()\n\n        if is_cuda_and_apex_available():\n            testargs.append("--fp16")\n\n        run_command(self._launch_args + testargs)\n        result = get_results(tmp_dir)\n        self.assertGreaterEqual(result["eval_accuracy"], 0.75)\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "epoch_0")))\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "glue_no_trainer")))\n\n    @mock.patch.dict(os.environ, {"WANDB_MODE": "offline"})\n    def test_run_clm_no_trainer(self):\n        tmp_dir = self.get_auto_remove_tmp_dir()\n        testargs = f"""\n            {self.examples_dir}/pytorch/language-modeling/run_clm_no_trainer.py\n            --model_name_or_path distilgpt2\n            --train_file ./tests/fixtures/sample_text.txt\n            --validation_file ./tests/fixtures/sample_text.txt\n            --block_size 128\n            --per_device_train_batch_size 5\n            --per_device_eval_batch_size 5\n            --num_train_epochs 2\n            --output_dir {tmp_dir}\n            --checkpointing_steps epoch\n            --with_tracking\n        """.split()\n\n        if torch.cuda.device_count() > 1:\n            # Skipping because there are not enough batches to train the model + would need a drop_last to work.\n            return\n\n        run_command(self._launch_args + testargs)\n        result = get_results(tmp_dir)\n        self.assertLess(result["perplexity"], 100)\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "epoch_0")))\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "clm_no_trainer")))\n\n    @mock.patch.dict(os.environ, {"WANDB_MODE": "offline"})\n    def test_run_mlm_no_trainer(self):\n        tmp_dir = self.get_auto_remove_tmp_dir()\n        testargs = f"""\n            {self.examples_dir}/pytorch/language-modeling/run_mlm_no_trainer.py\n            --model_name_or_path distilroberta-base\n            --train_file ./tests/fixtures/sample_text.txt\n            --validation_file ./tests/fixtures/sample_text.txt\n            --output_dir {tmp_dir}\n            --num_train_epochs=1\n            --checkpointing_steps epoch\n            --with_tracking\n        """.split()\n\n        run_command(self._launch_args + testargs)\n        result = get_results(tmp_dir)\n        self.assertLess(result["perplexity"], 42)\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "epoch_0")))\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "mlm_no_trainer")))\n\n    @mock.patch.dict(os.environ, {"WANDB_MODE": "offline"})\n    def test_run_ner_no_trainer(self):\n        # with so little data distributed training needs more epochs to get the score on par with 0/1 gpu\n        epochs = 7 if get_gpu_count() > 1 else 2\n\n        tmp_dir = self.get_auto_remove_tmp_dir()\n        testargs = f"""\n            {self.examples_dir}/pytorch/token-classification/run_ner_no_trainer.py\n            --model_name_or_path bert-base-uncased\n            --train_file tests/fixtures/tests_samples/conll/sample.json\n            --validation_file tests/fixtures/tests_samples/conll/sample.json\n            --output_dir {tmp_dir}\n            --learning_rate=2e-4\n            --per_device_train_batch_size=2\n            --per_device_eval_batch_size=2\n            --num_train_epochs={epochs}\n            --seed 7\n            --checkpointing_steps epoch\n            --with_tracking\n        """.split()\n\n        run_command(self._launch_args + testargs)\n        result = get_results(tmp_dir)\n        self.assertGreaterEqual(result["eval_accuracy"], 0.75)\n        self.assertLess(result["train_loss"], 0.5)\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "epoch_0")))\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "ner_no_trainer")))\n\n    @is_flaky()\n    @mock.patch.dict(os.environ, {"WANDB_MODE": "offline"})\n    def test_run_squad_no_trainer(self):\n        tmp_dir = self.get_auto_remove_tmp_dir()\n        testargs = f"""\n            {self.examples_dir}/pytorch/question-answering/run_qa_no_trainer.py\n            --model_name_or_path bert-base-uncased\n            --version_2_with_negative\n            --train_file tests/fixtures/tests_samples/SQUAD/sample.json\n            --validation_file tests/fixtures/tests_samples/SQUAD/sample.json\n            --output_dir {tmp_dir}\n            --max_train_steps=10\n            --num_warmup_steps=2\n            --learning_rate=2e-4\n            --per_device_train_batch_size=2\n            --per_device_eval_batch_size=1\n            --checkpointing_steps epoch\n            --with_tracking\n        """.split()\n\n        run_command(self._launch_args + testargs)\n        result = get_results(tmp_dir)\n        # Because we use --version_2_with_negative the testing script uses SQuAD v2 metrics.\n        self.assertGreaterEqual(result["eval_f1"], 28)\n        self.assertGreaterEqual(result["eval_exact"], 28)\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "epoch_0")))\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "qa_no_trainer")))\n\n    @mock.patch.dict(os.environ, {"WANDB_MODE": "offline"})\n    def test_run_swag_no_trainer(self):\n        tmp_dir = self.get_auto_remove_tmp_dir()\n        testargs = f"""\n            {self.examples_dir}/pytorch/multiple-choice/run_swag_no_trainer.py\n            --model_name_or_path bert-base-uncased\n            --train_file tests/fixtures/tests_samples/swag/sample.json\n            --validation_file tests/fixtures/tests_samples/swag/sample.json\n            --output_dir {tmp_dir}\n            --max_train_steps=20\n            --num_warmup_steps=2\n            --learning_rate=2e-4\n            --per_device_train_batch_size=2\n            --per_device_eval_batch_size=1\n            --with_tracking\n        """.split()\n\n        run_command(self._launch_args + testargs)\n        result = get_results(tmp_dir)\n        self.assertGreaterEqual(result["eval_accuracy"], 0.8)\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "swag_no_trainer")))\n\n    @slow\n    @mock.patch.dict(os.environ, {"WANDB_MODE": "offline"})\n    def test_run_summarization_no_trainer(self):\n        tmp_dir = self.get_auto_remove_tmp_dir()\n        testargs = f"""\n            {self.examples_dir}/pytorch/summarization/run_summarization_no_trainer.py\n            --model_name_or_path t5-small\n            --train_file tests/fixtures/tests_samples/xsum/sample.json\n            --validation_file tests/fixtures/tests_samples/xsum/sample.json\n            --output_dir {tmp_dir}\n            --max_train_steps=50\n            --num_warmup_steps=8\n            --learning_rate=2e-4\n            --per_device_train_batch_size=2\n            --per_device_eval_batch_size=1\n            --checkpointing_steps epoch\n            --with_tracking\n        """.split()\n\n        run_command(self._launch_args + testargs)\n        result = get_results(tmp_dir)\n        self.assertGreaterEqual(result["eval_rouge1"], 10)\n        self.assertGreaterEqual(result["eval_rouge2"], 2)\n        self.assertGreaterEqual(result["eval_rougeL"], 7)\n        self.assertGreaterEqual(result["eval_rougeLsum"], 7)\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "epoch_0")))\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "summarization_no_trainer")))\n\n    @slow\n    @mock.patch.dict(os.environ, {"WANDB_MODE": "offline"})\n    def test_run_translation_no_trainer(self):\n        tmp_dir = self.get_auto_remove_tmp_dir()\n        testargs = f"""\n            {self.examples_dir}/pytorch/translation/run_translation_no_trainer.py\n            --model_name_or_path sshleifer/student_marian_en_ro_6_1\n            --source_lang en\n            --target_lang ro\n            --train_file tests/fixtures/tests_samples/wmt16/sample.json\n            --validation_file tests/fixtures/tests_samples/wmt16/sample.json\n            --output_dir {tmp_dir}\n            --max_train_steps=50\n            --num_warmup_steps=8\n            --learning_rate=3e-3\n            --per_device_train_batch_size=2\n            --per_device_eval_batch_size=1\n            --source_lang en_XX\n            --target_lang ro_RO\n            --checkpointing_steps epoch\n            --with_tracking\n        """.split()\n\n        run_command(self._launch_args + testargs)\n        result = get_results(tmp_dir)\n        self.assertGreaterEqual(result["eval_bleu"], 30)\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "epoch_0")))\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "translation_no_trainer")))\n\n    @slow\n    def test_run_semantic_segmentation_no_trainer(self):\n        stream_handler = logging.StreamHandler(sys.stdout)\n        logger.addHandler(stream_handler)\n\n        tmp_dir = self.get_auto_remove_tmp_dir()\n        testargs = f"""\n            {self.examples_dir}/pytorch/semantic-segmentation/run_semantic_segmentation_no_trainer.py\n            --dataset_name huggingface/semantic-segmentation-test-sample\n            --output_dir {tmp_dir}\n            --max_train_steps=10\n            --num_warmup_steps=2\n            --learning_rate=2e-4\n            --per_device_train_batch_size=2\n            --per_device_eval_batch_size=1\n            --checkpointing_steps epoch\n        """.split()\n\n        run_command(self._launch_args + testargs)\n        result = get_results(tmp_dir)\n        self.assertGreaterEqual(result["eval_overall_accuracy"], 0.10)\n\n    @mock.patch.dict(os.environ, {"WANDB_MODE": "offline"})\n    def test_run_image_classification_no_trainer(self):\n        tmp_dir = self.get_auto_remove_tmp_dir()\n        testargs = f"""\n            {self.examples_dir}/pytorch/image-classification/run_image_classification_no_trainer.py\n            --model_name_or_path google/vit-base-patch16-224-in21k\n            --dataset_name hf-internal-testing/cats_vs_dogs_sample\n            --learning_rate 1e-4\n            --per_device_train_batch_size 2\n            --per_device_eval_batch_size 1\n            --max_train_steps 2\n            --train_val_split 0.1\n            --seed 42\n            --output_dir {tmp_dir}\n            --with_tracking\n            --checkpointing_steps 1\n        """.split()\n\n        if is_cuda_and_apex_available():\n            testargs.append("--fp16")\n\n        run_command(self._launch_args + testargs)\n        result = get_results(tmp_dir)\n        # The base model scores a 25%\n        self.assertGreaterEqual(result["eval_accuracy"], 0.6)\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "step_1")))\n        self.assertTrue(os.path.exists(os.path.join(tmp_dir, "image_classification_no_trainer")))\n',
        }
